@ARTICLE{10.1021/acs.nanolett.4c03692,
	author = {Yan J and Yu J and Bu C and Yang L and Chen J and Ding X and Yuan P},
	title = {Antibiotic-Augmented Chemodynamic Therapy for Treatment of Helicobacter pylori Infection in the Dynamic Stomach Environment.},
	journal = {Nano Lett},
	year = {2024},
	abstract = {Helicobacter pylori (H. pylori) is one of the main causes of peptic ulcer disease and gastric cancer. The overuse of antibiotics leads to bacterial drug resistance and disruption to the gut microbiome. Herein, a nanoparticle (TA-FeHMSN@Amox) was developed, comprising amoxicillin (Amox)-loaded iron-engineered hollow mesoporous silica as the core and a metal-polyphenol shell formed by tannic acid (TA) and Fe3+. In acidic stomach conditions, TA-FeHMSN@Amox generates bactericidal ·OH through Fenton/Fenton-like reactions of the degraded product Fe2+ and hydrogen peroxide (H2O2) at the infection site, achieving chemodynamic therapy (CDT). Moreover, released amoxicillin enhances therapeutic efficacy by impeding the self-repair of the bacterial cell wall damaged by CDT, overcoming the limitations of ineffective CDT under conditions lacking sufficient acidity and H2O2. The acidity-responsive CDT combined with reduced antibiotic usage ensures superior in vivo therapeutic efficacy and biocompatibility with intestinal flora, providing a highly potent strategy for treating H. pylori infections in the dynamic stomach environment.},
	doi = {10.1021/acs.nanolett.4c03692},
	pmid = {39541155 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ijbiomac.2024.137043,
	author = {Wang XY and Chen AQ and Huang J and Luo JH and Zou Q},
	title = {A review on structure, bioactivity, mechanism, structure-activity relationship and application of anti-breast cancer polysaccharides.},
	journal = {Int J Biol Macromol},
	year = {2024},
	abstract = {Breast cancer (BC) is one of the most common female malignant tumors. BC treatment depends on the use of chemotherapeutic drugs, causing various adverse effects. Increasing evidence has shown that natural polysaccharides (NPs) are potential adjuvants or substitutes for anti-BC drugs. However, the information regarding anti-BC NPs remains scattered. Thus, the recent progress in the structure, bioactivity, mechanism and application of anti-BC NPs is comprehensively summarized in this review. Moreover, the structure-activity relationship is discussed. Additionally, the prospects for future work are proposed. Recent studies have shown that anti-BC NPs have diverse structural features, which are affected by the extraction and purification methods. NPs show anti-BC activities in cell and animal experiments as well as in clinical researches, and enhance anti-BC effects of chemotherapeutic drugs in cell and animal experiments. The anti-BC mechanisms of NPs include anti-proliferation, inducing apoptosis, anti-metastasis and anti-invasion, immunoenhancement, gut microbiota regulation and others. The anti-BC activities of NPs are influenced by molecular weight, monosaccharide composition, functional groups, glycosidic bond types, backbone and side chains. NPs-based nanoparticles, nanocarriers, drug delivery systems, nanocomposites and other materials can also be used in anti-BC. This review provides theoretical bases for future research and functional application of NPs in anti-BC.},
	doi = {10.1016/j.ijbiomac.2024.137043},
	pmid = {39476909 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jep.2024.119008,
	author = {Tang X and He M and Ren Y and Ji M and Yan X and Zeng W and Lv Y and Li Y and He Y},
	title = {Traditional Chinese Medicine formulas-based interventions on colorectal carcinoma prevention: The efficacies, mechanisms and advantages.},
	journal = {J Ethnopharmacol},
	year = {2025},
	abstract = {ETHNOPHARMACOLOGICAL RELEVANCE: The Traditional Chinese Medicine Formulas (TCMFs) represent a distinctive medical approach to disease treatment and have been utilized in clinical practice for treating intestinal diseases for thousands of years. Recently, TCMFs have received increasing attention due to their advantages of high efficiency, safety, as well as low toxicity, providing promising strategies for preventing colorectal carcinoma (CRC). Nonetheless, the potential mechanism of TCMFs in preventing CRC has not been fully elucidated. AIM OF THE STUDY: The literature from the past three years was reviewed to highlight the therapeutic effects and underlying mechanisms of TCMFs in preventing CRC. MATERIALS AND METHODS: The keywords have been searched, including "traditional Chinese medicine formulas," "herb pairs," "Herbal plant-derived nanoparticles," et al. in "PubMed" and "China National Knowledge Infrastructure (CNKI)," and screened published articles related to the treatment of intestinal precancerous lesions. This review primarily examined the effectiveness and mechanisms of TCMFs in treating intestinal precancerous lesions, highlighting their significant potential in preventing CRC. RESULTS: Gegen Qinlian decoction, Shaoyao decoction, Wu Wei Wan, etc., exert substantial therapeutic effects on intestinal precancerous lesions. These therapeutic effects are demonstrated by a reduction in disease activity index scores, suppression of intestinal inflammation, and preservation of body weight and intestinal function, all of which contribute to the effective prevention of CRC. Besides, the classic Chinese herbal pairs and the extracellular vesicle-like nanoparticles of herbaceous plants have demonstrated superior efficacy in the treatment of intestinal precancerous lesions. Mechanistically, protecting the epithelial barrier, regulating gut microbiota as well as related metabolism, modulating macrophage polarization, and maintaining immune balance contribute to the role of TCMFs in CRC prevention. CONCLUSIONS: This review demonstrates the great potential and mechanism of TCMFs in CRC prevention and provides a scientific basis for their utilization in CRC prevention.},
	doi = {10.1016/j.jep.2024.119008},
	pmid = {39471879 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.heliyon.2024.e32390,
	author = {Okpoghono J and Isoje EF and Igbuku UA and Ekayoda O and Omoike GO and Adonor TO and Igue UB and Okom SU and Ovowa FO and Stephen-Onojedje QO and Ejueyitsi EO and Seigha AA},
	title = {Natural polyphenols: A protective approach to reduce colorectal cancer.},
	journal = {Heliyon},
	year = {2024},
	abstract = {BACKGROUND: A form of cancer that affects the rectum or colon (large intestine) is called colorectal cancer (CRC). The main risk factors for CRC include dietary, lifestyle, and environmental variables. Currently natural polyphenols have demonstrated impressive anticarcinogenic capabilities. OBJECTIVE: The main objective was to provide an updated, thorough assessment of the defensive mechanism of natural polyphenols for the global suppression of colorectal cancer. More precisely, this study aimed to analyze a set of chosen polyphenols with demonstrated safety, effectiveness, and biochemical defense mechanism on colon cancer models in order to facilitate future research. METHODS: This review was carried out with purposefully attentive and often updated scientific databases, including PubMed, Scopus, Science Direct, and Web of Science. After selecting approximately 178 potentially relevant papers based just on abstracts, 145 studies were meticulously reviewed and discussed. RESULTS: The outcomes disclosed that anti-CRC mechanisms of natural polyphenols involved the control of several molecular and signaling pathways. Natural polyphenols have also been shown to have the ability to limit the growth and genesis of tumors via altering the gut microbiota and cancer stem cells. However, the biochemical uses of many natural polyphenols have remained restricted because of their truncated water solubility and low bioavailability. In order to attain synergistic properties it is recommended to combine the use of different natural polyphenols because of their low bioavailability and volatility. However, the use of lipid-based nano- and micro-carriers also may be helpful to solve these problems with efficient distribution system to target sites. CONCLUSION: In conclusion, the use of polyphenols for CRC treatment appears promising. To ascertain their efficacy, more clinical research is anticipated.},
	doi = {10.1016/j.heliyon.2024.e32390},
	pmid = {38961927},
	note = {PMC11219337}
}

@ARTICLE{10.1016/j.scib.2024.06.016,
	author = {Chen L and Kang Z and Shen J and Zhao R and Miao Y and Zhang L and Zheng Z and Zhang Z and Liu N and Wang C and Fang H and Zhou J and Wang Y and Liu Z and Yang Y and Chen Q},
	title = {An emerging antibacterial nanovaccine for enhanced chemotherapy by selectively eliminating tumor-colonizing bacteria.},
	journal = {Sci Bull (Beijing)},
	year = {2024},
	abstract = {Fusobacterium nucleatum (F. nucleatum), an oral anaerobe, is prevalent in colorectal cancer and is closely related to increased cancer cell growth, metastasis, and poor treatment outcomes. Bacterial vaccines capable of selectively eliminating bacteria present a promising approach to targeting intratumor F. nucleatum, thereby enhancing cancer treatment. Although adjuvants have been employed to enhance the immune response, the vaccine's effectiveness is constrained by inadequate T-cell activation necessary for eradicating intracellular pathogens. In this study, we developed a minimalistic, biomimetic nanovaccine by integrating highly immunostimulatory adjuvant cholesterol-modified CpG oligonucleotides into the autologously derived F. nucleatum membranes. Compared to the traditional vaccines consisting of inactivated bacteria and Alum adjuvant, the nanovaccine coupled with bacterial membranes and adjuvants could remarkably improve multiple antigens and adjuvant co-delivery to dendritic cells, maximizing their ability to achieve effective antigen presentation and strong downstream immune progress. Notably, the nanovaccine exhibits outstanding selective prophylactic and therapeutic effects, eliminating F. nucleatum without affecting intratumoral and gut microbiota. It significantly enhances chemotherapy efficacy and reduces cancer metastasis in F. nucleatum-infected colorectal cancer. Overall, this work represents the rational application of bacterial nanovaccine and provides a blueprint for future development in enhancing the antitumor effect against bacterial-infected cancer.},
	doi = {10.1016/j.scib.2024.06.016},
	pmid = {38918142 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/lambio/ovae049,
	author = {Boyanova L and Medeiros J and Yordanov D and Gergova R and Markovska R},
	title = {Turmeric and curcumin as adjuncts in controlling Helicobacter pylori-associated diseases: a narrative review.},
	journal = {Lett Appl Microbiol},
	year = {2024},
	abstract = {Non-antibiotic adjuncts may improve Helicobacter pylori infection control. Our aim was to emphasize curcumin benefits in controlling H. pylori infection. We discussed publications in English mostly published since 2020 using keyword search. Curcumin is the main bioactive substance in turmeric. Curcumin inhibited H. pylori growth, urease activity, three cag genes, and biofilms through dose- and strain-dependent activities. Curcumin also displayed numerous anticancer activities such as apoptosis induction, anti-inflammatory and anti-angiogenic effects, caspase-3 upregulation, Bax protein enhancement, p53 gene activation, and chemosensitization. Supplementing triple regimens, the agent increased H. pylori eradication success in three Iranian studies. Bioavailability was improved by liposomal preparations, lipid conjugates, electrospray-encapsulation, and nano-complexation with proteins. The agent was safe at doses of 0.5->4 g daily, the most common (in 16% of the users) adverse effect being gastrointestinal upset. Notably, curcumin favorably influences the intestinal microbiota and inhibits Clostridioides difficile. Previous reports showed the inhibitory effect of curcumin on H pylori growth. Curcumin may become an additive in the therapy of H. pylori infection, an adjunct for gastric cancer control, and an agent beneficial to the intestinal microbiota. Further examination is necessary to determine its optimal dosage, synergy with antibiotics, supplementation to various eradication regimens, and prophylactic potential.},
	doi = {10.1093/lambio/ovae049},
	pmid = {38794899 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/antiox13040417,
	author = {Shen J and Jiao W and Yuan B and Xie H and Chen Z and Wei M and Sun Y and Wu Y and Zhang F and Li Z and Jin X and Du L and Jin Y},
	title = {Oral Curcumin-Thioketal-Inulin Conjugate Micelles against Radiation-Induced Enteritis.},
	journal = {Antioxidants (Basel)},
	year = {2024},
	abstract = {Radiation-induced enteritis is an unavoidable complication associated with pelvic tumor radiotherapy, significantly influencing the prognosis of cancer patients. The limited availability of commercial gastrointestinal radioprotectors in clinical settings poses a substantial challenge in preventing radiation enteritis. Despite the inherent radioprotective characteristics of Cur in vitro, its poor solubility in water, instability, and low bioavailability lead to inferior therapeutic effects in vivo. Herein, we developed novel ROS-responsive micelles (CTI) from inulin and curcumin, aimed at mitigating radiation enteritis. CTI micelles had excellent solubility and stability. Importantly, CTI improved the cytotoxicity and bioavailability of curcumin, thereby showing enhanced effectiveness in neutralizing ROS induced by radiation, safeguarding against DNA damage, and reducing radiation-induced cellular mortality. Moreover, in a radiation enteritis mice model, CTI not only alleviated severe radiation-induced intestinal injury but also improved redox-related indicators and reduced inflammatory cytokine expression. Furthermore, CTI effectively increased gut microbiota abundance and maintained gut homeostasis. In conclusion, CTI could be a promising candidate for the clinical management of radiation enteritis. Our study provides a new perspective for radioprotection using natural antioxidants.},
	doi = {10.3390/antiox13040417},
	pmid = {38671865},
	note = {PMC11047665}
}
